INSERT INTO lessons (id, course_id, unit, lesson_number, type, content) VALUES
(gen_random_uuid(), (SELECT id FROM courses WHERE title->>'ja' = 'JLPT N5 基本文法' LIMIT 1), 1, 1, 'grammar', '{"intro": {"ja": "日本語の基本的な文構造を学びます。です/ますは敬語の終助詞です。患者さんや同僚との丁寧な会話に必須です。介護現場では常に敬語が求められます。", "vi": "Học cấu trúc cơ bản của câu tiếng Nhật. です/ます là hạt kết thúc lịch sự. Cần thiết cho trò chuyện lịch sự với bệnh nhân hoặc đồng nghiệp. Tại cơ sở chăm sóc, luôn cần sử dụng lịch sự."}, "patterns": [{"pattern": "名詞 + です", "meaning": {"ja": "名詞の敬語形。～である", "vi": "Dạng lịch sự của danh từ. Là/là"}, "examples": [{"ja": "私は介護職です。", "vi": "Tôi là nhân viên chăm sóc."},{"ja": "これは薬です。", "vi": "Đây là thuốc."}], "care_context": "患者さんへの自己紹介時に使う：「私は太郎です。介護職です。」", "explanation": {"ja": "名詞にですを付けることで、敬語の説明文になります。介護職が患者さんと会話する時の基本です。", "vi": "Bằng cách thêm です vào danh từ, nó trở thành một câu giải thích lịch sự. Là cơ bản khi nhân viên chăm sóc nói chuyện với bệnh nhân."}, "difficulty": "easy"}, {"pattern": "動詞 + ます", "meaning": {"ja": "動詞の敬語形。～する", "vi": "Dạng lịch sự của động từ. Làm"}, "examples": [{"ja": "朝、患者さんを起こします。", "vi": "Sáng, tôi thức dậy bệnh nhân."},{"ja": "薬を飲みます。", "vi": "Uống thuốc."}], "care_context": "患者さんへの指示時に使う：「お水を飲みます。」", "explanation": {"ja": "動詞にますを付けることで、敬語の動作文になります。ます形は患者さんとの会話で常に使われます。", "vi": "Bằng cách thêm ます vào động từ, nó trở thành một câu hành động lịch sự. Dạng ます luôn được sử dụng trong trò chuyện với bệnh nhân."}, "difficulty": "easy"}, {"pattern": "形容詞 + です", "meaning": {"ja": "形容詞の敬語形。～い状態である", "vi": "Dạng lịch sự của tính từ. Là tình trạng ~ i"}, "examples": [{"ja": "今日は暑いです。", "vi": "Hôm nay trời nóng."},{"ja": "患者さんは元気です。", "vi": "Bệnh nhân khỏe mạnh."}], "care_context": "患者さんの状態を説明する時：「気分はいいですか？」", "explanation": {"ja": "い形容詞にですを付けて、敬語の説明文になります。患者さんの状態や感覚を聞く時に使えます。", "vi": "Bằng cách thêm です vào tính từ い, nó trở thành một câu giải thích lịch sự. Có thể sử dụng khi hỏi tình trạng hoặc cảm giác của bệnh nhân."}, "difficulty": "medium"}, {"pattern": "N1 は N2 です", "meaning": {"ja": "主語と述語の構造。～は～である", "vi": "Cấu trúc chủ ngữ và tân ngữ. ~ là ~"}, "examples": [{"ja": "私は介護職です。", "vi": "Tôi là nhân viên chăm sóc."},{"ja": "田中さんは患者さんです。", "vi": "Tanaka là bệnh nhân."}], "care_context": "患者さんのプロフィール説明時：「鈴木さんは80歳です。」", "explanation": {"ja": "は粒子は話題を示します。N1 は N2 ですで、主語と述語を結びます。基本的な文構造です。", "vi": "Trợ từ は chỉ chủ đề. N1 は N2 です kết nối chủ ngữ và vị ngữ. Đây là cấu trúc cơ bản."}, "difficulty": "easy"}], "dialogue": ["介護職: 「私は太郎です。あなたの介護職です。」", "患者さん: 「よろしくお願いします。」", "介護職: 「朝ですから、起きます。」", "患者さん: 「わかりました。」", "介護職: 「今日はいい天気です。」", "患者さん: 「そうですね。」", "介護職: 「では、朝食を食べます。」"], "key_phrases": [{"ja": "私は介護職です", "vi": "Tôi là nhân viên chăm sóc"},{"ja": "薬を飲みます", "vi": "Uống thuốc"},{"ja": "気分がいいです", "vi": "Cảm thấy tốt"},{"ja": "患者さんです", "vi": "Là bệnh nhân"}], "cultural_note": {"ja": "日本の介護では、敬語（敬意を示す言葉使い）が最も大切です。患者さんに対して常にです/ますを使うことが、患者さんへの尊重を示します。", "vi": "Trong chăm sóc tại Nhật Bản, lịch sự (cách sử dụng từ ngữ tôn trọng) là quan trọng nhất. Luôn sử dụng です/ます với bệnh nhân cho thấy sự tôn trọng."}, "quiz": [{"question": {"ja": "「です/ます」を使うのはなぜですか？", "vi": "Tại sao sử dụng \"です/ます\"?"}, "options": [{"ja": "簡単だから", "vi": "Bởi vì đơn giản"},{"ja": "敬意を示すため", "vi": "Để thể hiện sự tôn trọng"},{"ja": "時間を節約するため", "vi": "Để tiết kiệm thời gian"},{"ja": "難しいから", "vi": "Bởi vì khó"}], "correct_answer": 1, "explanation": {"ja": "です/ますは敬語です。患者さんへの尊重を表します。", "vi": "です/ます là lịch sự. Nó thể hiện sự tôn trọng đối với bệnh nhân."}, "difficulty": "easy"}]}');
INSERT INTO lessons (id, course_id, unit, lesson_number, type, content) VALUES
(gen_random_uuid(), (SELECT id FROM courses WHERE title->>'ja' = 'JLPT N5 基本文法' LIMIT 1), 1, 2, 'grammar', '{"intro": {"ja": "助詞は日本語の文法の基礎です。は、が、を の3つの重要な助詞を学びます。正確な助詞の使い分けが、患者さんとの正確な意思疎通を実現させます。", "vi": "Trợ từ là cơ sở của ngữ pháp tiếng Nhật. Học 3 trợ từ quan trọng: は、が、を. Sử dụng trợ từ một cách chính xác giúp giao tiếp chính xác với bệnh nhân."}, "patterns": [{"pattern": "助詞は", "meaning": {"ja": "主語（一般的な話題）を示す", "vi": "Chỉ chủ đề (chủ đề chung)"}, "examples": [{"ja": "私は介護職です。", "vi": "Tôi là nhân viên chăm sóc."},{"ja": "患者さんは80歳です。", "vi": "Bệnh nhân 80 tuổi."}], "care_context": "患者さんについて一般的に説明する時：「田中さんは糖尿病です。」", "explanation": {"ja": "は助詞は、一般的な主題を示します。患者さんについて話す時、基本的に は を使います。", "vi": "Trợ từ は chỉ chủ đề chung. Khi nói về bệnh nhân, cơ bản là sử dụng は."}, "difficulty": "easy"}, {"pattern": "助詞が", "meaning": {"ja": "新しい情報や強調される主語を示す", "vi": "Chỉ thông tin mới hoặc chủ ngữ được nhấn mạnh"}, "examples": [{"ja": "誰が来ましたか？太郎が来ました。", "vi": "Ai đến? Taro đến."},{"ja": "何が痛いですか？頭が痛いです。", "vi": "Cái gì đau? Đầu đau."}], "care_context": "患者さんの症状を確認する時：「どこが痛いですか？」「腰が痛いです。」", "explanation": {"ja": "が助詞は、新しい情報や特別な重点を示します。患者さんが何か新しい症状を報告する時に使われます。", "vi": "Trợ từ が chỉ thông tin mới hoặc nhấn mạnh đặc biệt. Được sử dụng khi bệnh nhân báo cáo triệu chứng mới."}, "difficulty": "medium"}, {"pattern": "助詞を", "meaning": {"ja": "目的語（行動の対象）を示す", "vi": "Chỉ tân ngữ (đối tượng của hành động)"}, "examples": [{"ja": "薬を飲みます。", "vi": "Uống thuốc."},{"ja": "食事を食べます。", "vi": "Ăn cơm."}], "care_context": "患者さんへの指示時：「この薬を飲んでください。」「水を飲みます。」", "explanation": {"ja": "を助詞は、動詞の対象を示します。何かをする時、その対象に を を付けます。", "vi": "Trợ từ を chỉ đối tượng của động từ. Khi làm gì đó, thêm を vào đối tượng."}, "difficulty": "easy"}], "dialogue": ["介護職: 「どこが痛いですか？」", "患者さん: 「腰が痛いです。」", "介護職: 「この薬を飲んでください。」", "患者さん: 「わかりました。」", "介護職: 「水を飲みますね。」", "患者さん: 「はい。」", "介護職: 「田中さんはいい患者さんです。」"], "key_phrases": [{"ja": "患者さんは元気です", "vi": "Bệnh nhân khỏe mạnh"},{"ja": "どこが痛いですか", "vi": "Cái gì đau"},{"ja": "薬を飲みます", "vi": "Uống thuốc"},{"ja": "水を飲んでください", "vi": "Vui lòng uống nước"}], "cultural_note": {"ja": "助詞の正確な使い分けは、患者さんとの意思疎通の精度を高めます。特に症状や痛みを聞く時、正確な助詞を使うことが誤解を防ぎます。", "vi": "Sử dụng trợ từ chính xác nâng cao độ chính xác giao tiếp với bệnh nhân. Đặc biệt khi hỏi về triệu chứng hoặc đau, sử dụng trợ từ chính xác ngăn chặn hiểu lầm."}, "quiz": [{"question": {"ja": "「どこが痛いですか？」と聞く時、何を強調していますか？", "vi": "Khi hỏi \"どこが痛いですか?\", điều gì được nhấn mạnh?"}, "options": [{"ja": "一般的な話題", "vi": "Chủ đề chung"},{"ja": "特定の痛い場所を強調", "vi": "Nhấn mạnh vị trí đau cụ thể"},{"ja": "行動の対象", "vi": "Đối tượng của hành động"},{"ja": "過去のこと", "vi": "Những thứ trong quá khứ"}], "correct_answer": 1, "explanation": {"ja": "が助詞は新しい情報や特定の場所を強調します。痛みの場所を特定する時に使われます。", "vi": "Trợ từ が nhấn mạnh thông tin mới hoặc vị trí cụ thể. Được sử dụng để xác định vị trí đau."}, "difficulty": "medium"}]}');
INSERT INTO lessons (id, course_id, unit, lesson_number, type, content) VALUES
(gen_random_uuid(), (SELECT id FROM courses WHERE title->>'ja' = 'JLPT N5 基本文法' LIMIT 1), 2, 1, 'grammar', '{"intro": {"ja": "時間に関する表現を学びます。～時に、～まで、～から は、スケジュール管理と患者さんへの指示に不可欠です。介護の日常では、いつ何をするかを正確に伝える必要があります。", "vi": "Học các biểu thức liên quan thời gian. ~時に、~まで、~から là cần thiết để quản lý lịch trình và chỉ dẫn bệnh nhân. Trong cuộc sống hàng ngày của chăm sóc, cần phải truyền đạt chính xác khi nào làm gì."}, "patterns": [{"pattern": "～時に", "meaning": {"ja": "特定の時刻に。～の時に", "vi": "Vào một thời điểm cụ thể"}, "examples": [{"ja": "8時に朝食を食べます。", "vi": "Ăn bữa sáng lúc 8 giờ."},{"ja": "10時に薬を飲みます。", "vi": "Uống thuốc lúc 10 giờ."}], "care_context": "患者さんのスケジュールを伝える時：「朝6時に起きます。」「12時に食事をします。」", "explanation": {"ja": "～時に は、特定の時刻や時期を表します。患者さんの1日のスケジュールを説明する時に使います。", "vi": "~時に biểu hiện một thời điểm hoặc thời kỳ cụ thể. Sử dụng khi giải thích lịch trình hàng ngày của bệnh nhân."}, "difficulty": "easy"}, {"pattern": "～まで", "meaning": {"ja": "終了時点まで。～の終わりまで", "vi": "Cho đến thời điểm kết thúc"}, "examples": [{"ja": "3時まで休みます。", "vi": "Nghỉ cho đến 3 giờ."},{"ja": "6月まで治療をします。", "vi": "Tiếp tục điều trị cho đến tháng 6."}], "care_context": "治療期間を説明する時：「この薬は1ヶ月まで飲みます。」", "explanation": {"ja": "～まで は、範囲や期間の終了地点を示します。治療期間やリハビリの期限を説明する時に使えます。", "vi": "~まで chỉ điểm kết thúc của phạm vi hoặc khoảng thời gian. Có thể sử dụng khi giải thích thời gian điều trị hoặc hạn chót phục hồi chức năng."}, "difficulty": "easy"}, {"pattern": "～から", "meaning": {"ja": "開始時点から。～の始まりから", "vi": "Từ thời điểm bắt đầu"}, "examples": [{"ja": "明日から新しい薬を飲みます。", "vi": "Từ ngày mai, uống thuốc mới."},{"ja": "10時からシャワーをします。", "vi": "Từ 10 giờ, tắm vòi sen."}], "care_context": "新しい治療やスケジュール変更を伝える時：「今週からリハビリを開始します。」", "explanation": {"ja": "～から は、範囲や期間の開始地点を示します。新しい活動やスケジュールの開始を説明する時に使います。", "vi": "~から chỉ điểm bắt đầu của phạm vi hoặc khoảng thời gian. Sử dụng khi giải thích bắt đầu của hoạt động mới hoặc lịch trình."}, "difficulty": "easy"}], "dialogue": ["介護職: 「朝6時に起きましょう。」", "患者さん: 「わかりました。」", "介護職: 「8時まで朝食の準備をします。」", "患者さん: 「ありがとうございます。」", "介護職: 「明日から新しいリハビリを開始します。」", "患者さん: 「頑張ります。」", "介護職: 「素晴らしい。一緒に頑張りましょう。」"], "key_phrases": [{"ja": "8時に朝食", "vi": "Bữa sáng lúc 8 giờ"},{"ja": "3時までリハビリ", "vi": "Phục hồi chức năng cho đến 3 giờ"},{"ja": "明日から新しい薬", "vi": "Từ ngày mai, thuốc mới"},{"ja": "1ヶ月まで治療", "vi": "Điều trị cho đến 1 tháng"}], "cultural_note": {"ja": "介護では、スケジュール管理が重要です。患者さんに明確な時間枠を提供することで、患者さんは安心感を持ち、生活のリズムが整います。", "vi": "Trong chăm sóc, quản lý lịch trình là quan trọng. Cung cấp khung thời gian rõ ràng cho bệnh nhân giúp họ cảm thấy an tâm và cuộc sống có nhịp độ."}, "quiz": [{"question": {"ja": "「8時に朝食を食べます」は何を意味していますか？", "vi": "\"8時に朝食を食べます\" có nghĩa là gì?"}, "options": [{"ja": "8時までずっと食べる", "vi": "Ăn cho đến 8 giờ"},{"ja": "8時からずっと食べる", "vi": "Ăn từ 8 giờ"},{"ja": "8時の時点で朝食を食べる", "vi": "Ăn bữa sáng vào lúc 8 giờ"},{"ja": "8時の後で食べる", "vi": "Ăn sau 8 giờ"}], "correct_answer": 2, "explanation": {"ja": "～時に は特定の時刻を示します。8時に朝食をするということは、8時の時点で朝食をするという意味です。", "vi": "~時に chỉ một thời điểm cụ thể. Ăn bữa sáng lúc 8 giờ có nghĩa là ăn bữa sáng vào thời điểm 8 giờ."}, "difficulty": "medium"}]}');
INSERT INTO lessons (id, course_id, unit, lesson_number, type, content) VALUES
(gen_random_uuid(), (SELECT id FROM courses WHERE title->>'ja' = 'JLPT N5 基本文法' LIMIT 1), 2, 2, 'grammar', '{"intro": {"ja": "理由や目的を表す表現を学びます。～から、～ので、～ため は患者さんに医療行為やケアの理由を説明する時に重要です。患者さんが理由を理解することで、より協力的になります。", "vi": "Học các biểu thức biểu hiện lý do hoặc mục đích. ~から、~ので、~ため là quan trọng khi giải thích lý do của các hành động y tế hoặc chăm sóc cho bệnh nhân. Khi bệnh nhân hiểu lý do, họ sẽ hợp tác hơn."}, "patterns": [{"pattern": "～から", "meaning": {"ja": "理由を示す。～だから", "vi": "Chỉ lý do. Vì ~"}, "examples": [{"ja": "風邪だから、薬を飲みます。", "vi": "Vì bị cảm cúm, nên uống thuốc."},{"ja": "高血圧だから、塩辛い食べ物は避けます。", "vi": "Vì cao huyết áp, nên tránh thực phẩm mặn."}], "care_context": "患者さんに治療の理由を説明する時：「血糖値が高いから、この食事制限をしています。」", "explanation": {"ja": "～から は理由や原因を示します。因果関係を説明する時に使われます。", "vi": "~から chỉ lý do hoặc nguyên nhân. Được sử dụng khi giải thích quan hệ nhân quả."}, "difficulty": "medium"}, {"pattern": "～ので", "meaning": {"ja": "理由を示す（敬語）。～だから（より丁寧）", "vi": "Chỉ lý do (lịch sự). Vì ~ (lịch sự hơn)"}, "examples": [{"ja": "患者さんが疲れているので、ゆっくり進みます。", "vi": "Vì bệnh nhân mệt mỏi, nên tiến từ từ."},{"ja": "天気がいいので、散歩に行きましょう。", "vi": "Vì thời tiết tốt, nên đi dạo."}], "care_context": "患者さんに丁寧に理由を説明する時：「血圧が高いので、塩を控えてください。」", "explanation": {"ja": "～ので は ～から と同じく理由を示しますが、より敬語的で丁寧です。患者さんとの会話では、～ので を使うことがより適切です。", "vi": "~ので chỉ lý do giống như ~から, nhưng lịch sự hơn. Trong trò chuyện với bệnh nhân, sử dụng ~ので là thích hợp hơn."}, "difficulty": "medium"}, {"pattern": "～ため", "meaning": {"ja": "目的を示す。～するために", "vi": "Chỉ mục đích. Để ~"}, "examples": [{"ja": "健康のため、毎日散歩をします。", "vi": "Để sức khỏe, đi dạo hàng ngày."},{"ja": "リハビリのため、運動をしています。", "vi": "Để phục hồi chức năng, tôi đang tập luyện."}], "care_context": "患者さんに治療の目的を説明する時：「体力を回復させるため、リハビリを行っています。」", "explanation": {"ja": "～ため は目的や意図を示します。何かをする理由が、その目的にあることを説明する時に使われます。", "vi": "~ため chỉ mục đích hoặc ý định. Được sử dụng khi giải thích rằng lý do làm gì đó là mục đích đó."}, "difficulty": "medium"}], "dialogue": ["介護職: 「血糖値が高いので、甘い食べ物は控えてください。」", "患者さん: 「わかりました。」", "介護職: 「体力を回復させるため、毎日リハビリをしています。」", "患者さん: 「頑張ります。」", "介護職: 「天気がいいので、今日は散歩に行きましょう。」", "患者さん: 「ありがとうございます。」", "介護職: 「患者さんの健康のため、最善を尽くします。」"], "key_phrases": [{"ja": "高血圧だから、塩を控える", "vi": "Vì cao huyết áp, nên giảm muối"},{"ja": "体力を回復させるため、リハビリ", "vi": "Để phục hồi thể lực, phục hồi chức năng"},{"ja": "健康のため、散歩をする", "vi": "Để sức khỏe, đi dạo"},{"ja": "疲れているので、ゆっくり進む", "vi": "Vì mệt mỏi, nên tiến từ từ"}], "cultural_note": {"ja": "患者さんに理由や目的を丁寧に説明することで、患者さんは医療行為やケアに協力しやすくなります。患者さんの理解と納得は、介護の質を高めるために不可欠です。", "vi": "Giải thích lý do hoặc mục đích một cách lịch sự cho bệnh nhân giúp họ hợp tác dễ dàng hơn với hành động y tế hoặc chăm sóc. Sự hiểu biết và sự đồng ý của bệnh nhân là cần thiết để nâng cao chất lượng chăm sóc."}, "quiz": [{"question": {"ja": "「血糖値が高いので、甘い食べ物は控えてください」という説明は何を示していますか？", "vi": "Giải thích \"血糖値が高いので、甘い食べ物は控えてください\" chỉ cái gì?"}, "options": [{"ja": "目的を示す", "vi": "Chỉ mục đích"},{"ja": "理由を示す", "vi": "Chỉ lý do"},{"ja": "時間を示す", "vi": "Chỉ thời gian"},{"ja": "場所を示す", "vi": "Chỉ nơi chốn"}], "correct_answer": 1, "explanation": {"ja": "「高いから」という理由で「甘い食べ物を控える」ということを説明しています。", "vi": "Giải thích rằng \"vì cao huyết áp\" nên \"giảm thực phẩm ngọt\"."}, "difficulty": "medium"}]}');
INSERT INTO lessons (id, course_id, unit, lesson_number, type, content) VALUES
(gen_random_uuid(), (SELECT id FROM courses WHERE title->>'ja' = 'JLPT N5 基本文法' LIMIT 1), 3, 1, 'grammar', '{"intro": {"ja": "目的語を示す助詞を学びます。を、に、で は、患者さんへの指示や説明で頻繁に使われます。これらの助詞を正確に使い分けることで、患者さんは正確に理解できます。", "vi": "Học các trợ từ chỉ tân ngữ. を、に、で được sử dụng thường xuyên trong chỉ dẫn hoặc giải thích cho bệnh nhân. Sử dụng chúng chính xác giúp bệnh nhân hiểu rõ."}, "patterns": [{"pattern": "助詞を", "meaning": {"ja": "直接的な目的語。～を動詞", "vi": "Tân ngữ trực tiếp. ~ động từ"}, "examples": [{"ja": "薬を飲みます。", "vi": "Uống thuốc."},{"ja": "食事を食べます。", "vi": "Ăn cơm."}], "care_context": "患者さんへの具体的な指示：「この薬を飲んでください。」「水を飲みます。」", "explanation": {"ja": "を は動詞の直接的な対象を示します。何かをする対象となるものに を を付けます。", "vi": "を chỉ đối tượng trực tiếp của động từ. Thêm を vào thứ là đối tượng làm gì đó."}, "difficulty": "easy"}, {"pattern": "助詞に", "meaning": {"ja": "移動の目的地。～に行く", "vi": "Địa điểm đích đến. Đi tới ~"}, "examples": [{"ja": "病院に行きます。", "vi": "Đi bệnh viện."},{"ja": "トイレに行ってください。", "vi": "Vui lòng đi nhà vệ sinh."}], "care_context": "患者さんへの指示：「検査室に行きます。」「リハビリ室に行きましょう。」", "explanation": {"ja": "に は移動の目的地を示します。どこへ行くのかを説明する時に使われます。", "vi": "に chỉ địa điểm đích đến của chuyển động. Được sử dụng khi giải thích nơi sẽ đi."}, "difficulty": "easy"}, {"pattern": "助詞で", "meaning": {"ja": "行為の場所や手段。～で動詞", "vi": "Nơi hoặc phương tiện của hành động. ~ động từ"}, "examples": [{"ja": "図書館で本を読みます。", "vi": "Đọc sách ở thư viện."},{"ja": "ペンで書きます。", "vi": "Viết bằng bút."}], "care_context": "患者さんへの説明：「食堂で食事をします。」「車で病院に行きます。」", "explanation": {"ja": "で は行為の場所や方法を示します。どこでするのか、どうやってするのかを説明する時に使われます。", "vi": "で chỉ nơi hoặc phương pháp của hành động. Được sử dụng khi giải thích nơi hoặc cách làm gì đó."}, "difficulty": "medium"}], "dialogue": ["介護職: 「この薬を飲んでください。」", "患者さん: 「わかりました。」", "介護職: 「次に病院に行きます。」", "患者さん: 「ありがとうございます。」", "介護職: 「車で行きますね。」", "患者さん: 「はい。」", "介護職: 「検査室で検査をします。」"], "key_phrases": [{"ja": "薬を飲む", "vi": "Uống thuốc"},{"ja": "病院に行く", "vi": "Đi bệnh viện"},{"ja": "車で移動", "vi": "Di chuyển bằng ô tô"},{"ja": "食堂で食事", "vi": "Ăn cơm ở nhà ăn"}], "cultural_note": {"ja": "助詞の正確な使い分けは、患者さんの安全と理解に直結します。移動先や手段を正確に伝えることで、患者さんの不安を軽減できます。", "vi": "Sử dụng trợ từ chính xác liên quan trực tiếp đến sự an toàn và sự hiểu biết của bệnh nhân. Truyền đạt chính xác nơi đến và phương tiện có thể giảm bớt lo lắng của bệnh nhân."}, "quiz": [{"question": {"ja": "「病院に行きます」の「に」は何を示していますか？", "vi": "\"に\" trong \"病院に行きます\" chỉ cái gì?"}, "options": [{"ja": "行為の手段", "vi": "Phương tiện của hành động"},{"ja": "目的地", "vi": "Địa điểm đích đến"},{"ja": "行為の場所", "vi": "Nơi của hành động"},{"ja": "直接的な目的語", "vi": "Tân ngữ trực tiếp"}], "correct_answer": 1, "explanation": {"ja": "に は移動の目的地を示します。病院がどこへ行く目的地であることを示しています。", "vi": "に chỉ địa điểm đích đến. Nó chỉ rằng bệnh viện là nơi đi tới."}, "difficulty": "easy"}]}');
INSERT INTO lessons (id, course_id, unit, lesson_number, type, content) VALUES
(gen_random_uuid(), (SELECT id FROM courses WHERE title->>'ja' = 'JLPT N5 基本文法' LIMIT 1), 3, 2, 'grammar', '{"intro": {"ja": "て形は複数の動作をつなぎます。～て、～ないで は、患者さんへの複合的な指示やケアの説明に使われます。一つの文で複数の行動をスムーズに説明できます。", "vi": "Dạng て kết nối nhiều hành động. ~て、~ないで được sử dụng trong các chỉ dẫn phức hợp hoặc giải thích chăm sóc cho bệnh nhân. Một câu có thể giải thích suôn sẻ nhiều hành động."}, "patterns": [{"pattern": "動詞て形 + 動詞", "meaning": {"ja": "複数の動作をつなぐ。順序を示す", "vi": "Kết nối nhiều hành động. Chỉ thứ tự"}, "examples": [{"ja": "起きて、顔を洗って、朝食を食べます。", "vi": "Thức dậy, rửa mặt, ăn bữa sáng."},{"ja": "薬を飲んで、休んでください。", "vi": "Uống thuốc, rồi nghỉ."}], "care_context": "患者さんの朝の流れを説明：「6時に起きて、洗顔して、朝食を食べて、薬を飲みます。」", "explanation": {"ja": "て形は複数の動作を順序立てて説明します。一つの文で患者さんの1日のルーチンを説明できます。", "vi": "Dạng て giải thích nhiều hành động theo thứ tự. Một câu có thể giải thích thói quen hàng ngày của bệnh nhân."}, "difficulty": "medium"}, {"pattern": "～ないで + 動詞", "meaning": {"ja": "～してはいけない。～する必要がない", "vi": "Không nên ~. Không cần ~"}, "examples": [{"ja": "走らないで、ゆっくり歩いてください。", "vi": "Đừng chạy, hãy đi từ từ."},{"ja": "パソコンを使わないで、休んでください。", "vi": "Đừng dùng máy tính, hãy nghỉ."}], "care_context": "患者さんへの注意：「無理をしないで、ゆっくり進んでください。」「水を飲まないで、食事をしてください。」", "explanation": {"ja": "～ないで は禁止や制限を表します。患者さんが避けるべき行動を説明する時に使われます。", "vi": "~ないで biểu hiện cấm hoặc hạn chế. Được sử dụng khi giải thích hành động nên tránh của bệnh nhân."}, "difficulty": "medium"}], "dialogue": ["介護職: 「6時に起きて、洗顔して、朝食を食べてください。」", "患者さん: 「わかりました。」", "介護職: 「走らないで、ゆっくり歩いてください。」", "患者さん: 「気をつけます。」", "介護職: 「薬を飲んで、休んでください。」", "患者さん: 「ありがとうございます。」", "介護職: 「無理をしないで、自分のペースで進んでください。」"], "key_phrases": [{"ja": "起きて、洗顔して、朝食", "vi": "Thức dậy, rửa mặt, bữa sáng"},{"ja": "走らないで、ゆっくり歩く", "vi": "Đừng chạy, đi từ từ"},{"ja": "薬を飲んで、休む", "vi": "Uống thuốc, rồi nghỉ"},{"ja": "無理をしないで、ペースで進む", "vi": "Đừng cố quá, tiến theo tốc độ"}], "cultural_note": {"ja": "複数の指示を一つの文でスムーズに説明することで、患者さんは理解しやすくなります。また、禁止事項を正確に伝えることは、患者さんの安全を確保します。", "vi": "Giải thích nhiều chỉ dẫn suôn sẻ trong một câu giúp bệnh nhân dễ hiểu hơn. Ngoài ra, truyền đạt chính xác những điều cấm giúp đảm bảo an toàn cho bệnh nhân."}, "quiz": [{"question": {"ja": "「起きて、顔を洗って、朝食を食べます」は何を示していますか？", "vi": "\"起きて、顔を洗って、朝食を食べます\" chỉ cái gì?"}, "options": [{"ja": "複数の動作を順序立てて説明", "vi": "Giải thích nhiều hành động theo thứ tự"},{"ja": "禁止を示す", "vi": "Chỉ cấm"},{"ja": "目的を示す", "vi": "Chỉ mục đích"},{"ja": "理由を示す", "vi": "Chỉ lý do"}], "correct_answer": 0, "explanation": {"ja": "て形は複数の動作をつなぎ、順序を示します。起きる → 洗顔 → 朝食という3つの行動を順序立てて説明しています。", "vi": "Dạng て kết nối nhiều hành động và chỉ thứ tự. Nó giải thích 3 hành động: thức dậy → rửa mặt → bữa sáng theo thứ tự."}, "difficulty": "medium"}]}');
INSERT INTO lessons (id, course_id, unit, lesson_number, type, content) VALUES
(gen_random_uuid(), (SELECT id FROM courses WHERE title->>'ja' = 'JLPT N5 基本文法' LIMIT 1), 4, 1, 'grammar', '{"intro": {"ja": "否定文は、何かを「しない」「できない」と言う時に使います。介護職として、患者さんの制限や禁止事項を説明する時に重要です。「これは食べてはいけません」「この薬は飲みません」など、安全なケアのために必要な表現です。", "vi": "Câu phủ định được sử dụng khi nói \"không làm\", \"không thể\". Quan trọng để giải thích những hạn chế hoặc cấm của bệnh nhân. \"Không được ăn cái này\", \"Không uống thuốc này\"... những biểu hiện cần thiết cho chăm sóc an toàn."}, "patterns": [{"pattern": "動詞 + ない", "meaning": {"ja": "動詞の否定形。～しない、～できない", "vi": "Dạng phủ định của động từ. Không làm, không thể"}, "examples": [{"ja": "食べない", "vi": "Không ăn"},{"ja": "飲まない", "vi": "Không uống"}], "care_context": "「この食べ物は食べてはいけません」など、患者さんの食事制限を説明する時", "explanation": {"ja": "動詞にないを付けることで、その行動をしないことを表します。", "vi": "Bằng cách thêm ない vào động từ, nó biểu hiện không làm hành động đó."}, "difficulty": "medium"}, {"pattern": "動詞 + ません", "meaning": {"ja": "敬語の否定形。丁寧に「～しません」と言う", "vi": "Dạng phủ định lịch sự. Nói một cách lịch sự \"Không làm\""}, "examples": [{"ja": "今日は来ません", "vi": "Hôm nay tôi không đến"},{"ja": "薬は飲みません", "vi": "Tôi không uống thuốc"}], "care_context": "患者さんに敬意を持ちながら、何かをしないことを説明する時", "explanation": {"ja": "ませんは敬語の否定形です。患者さんとの会話では、このます形を使うことが大切です。", "vi": "ません là dạng phủ định lịch sự. Khi trò chuyện với bệnh nhân, quan trọng là sử dụng dạng ます."}, "difficulty": "medium"}], "dialogue": ["患者さん: 「この食べ物は食べてもいいですか？」", "介護職: 「いいえ、その食べ物は食べてはいけません。」", "患者さん: 「そうですか。何か理由がありますか？」", "介護職: 「はい。あなたは高血圧ですから、塩辛い食べ物を食べません。」", "患者さん: 「わかりました。」", "介護職: 「でも、他の食べ物はたくさんありますから、大丈夫ですよ。」", "患者さん: 「ありがとうございます。」"], "key_phrases": [{"ja": "食べてはいけません", "vi": "Không được ăn"},{"ja": "飲みません", "vi": "Không uống"},{"ja": "来ません", "vi": "Không đến"},{"ja": "できません", "vi": "Không thể"}], "cultural_note": {"ja": "介護施設では、患者さんの食事制限や薬の禁止事項を正確に伝えることが、患者さんの安全と健康を守るために最も重要です。否定文を丁寧に説明することが必要です。", "vi": "Tại các cơ sở chăm sóc, cần phải truyền đạt chính xác những hạn chế chế độ ăn hoặc cấm thuốc của bệnh nhân để bảo vệ sự an toàn và sức khỏe. Giải thích câu phủ định một cách lịch sự là cần thiết."}, "quiz": [{"question": {"ja": "「ない」の意味は何ですか？", "vi": "Ý nghĩa của \"ない\" là gì?"}, "options": [{"ja": "肯定である", "vi": "Khẳng định"},{"ja": "行動をしないことを表す", "vi": "Biểu hiện không làm hành động"},{"ja": "過去である", "vi": "Quá khứ"},{"ja": "将来である", "vi": "Tương lai"}], "correct_answer": 1, "explanation": {"ja": "「ない」は動詞の否定形です。その行動をしないことを表します。", "vi": "\"ない\" là dạng phủ định của động từ. Nó biểu hiện không làm hành động đó."}, "difficulty": "easy"}]}');
INSERT INTO lessons (id, course_id, unit, lesson_number, type, content) VALUES
(gen_random_uuid(), (SELECT id FROM courses WHERE title->>'ja' = 'JLPT N5 基本文法' LIMIT 1), 4, 2, 'grammar', '{"intro": {"ja": "「ている」は、今現在進行している行動や、継続している状態を表します。「患者さんが今、食べています」「シャワーを浴びています」など、ケアの進行状況を説明する時に使います。", "vi": "\"ている\" biểu hiện những hành động đang diễn ra hiện tại hoặc những tình trạng đang kéo dài. \"Bệnh nhân đang ăn bây giờ\", \"Đang tắm\"... được sử dụng khi giải thích tiến trình chăm sóc."}, "patterns": [{"pattern": "動詞 + ている", "meaning": {"ja": "現在進行中の行動。今、その動作をしている", "vi": "Hành động đang tiến hành. Hiện tại đang làm hành động đó"}, "examples": [{"ja": "食べている", "vi": "Đang ăn"},{"ja": "飲んでいる", "vi": "Đang uống"}], "care_context": "「ご利用者様が今、食べています」など、患者さんの現在の状態を説明する時", "explanation": {"ja": "ている形は、現在その瞬間に起きている行動を表します。ケアの報告で非常に重要です。", "vi": "Dạng ている biểu hiện hành động đang xảy ra tại thời điểm hiện tại. Rất quan trọng trong báo cáo chăm sóc."}, "difficulty": "medium"}], "dialogue": ["スタッフA: 「田中さんはどこですか？」", "介護職: 「田中さんは今、シャワーを浴びています。」", "スタッフA: 「そうですか。いつ終わりますか？」", "介護職: 「あと10分くらいで終わると思います。」", "スタッフA: 「わかりました。」", "介護職: 「終わったら、私が声をかけます。」", "スタッフA: 「ありがとうございます。」"], "key_phrases": [{"ja": "食べています", "vi": "Đang ăn"},{"ja": "シャワーを浴びています", "vi": "Đang tắm"},{"ja": "休んでいます", "vi": "Đang nghỉ"},{"ja": "寝ています", "vi": "Đang ngủ"}], "cultural_note": {"ja": "患者さんの状況を正確に報告することは、スタッフ間のコミュニケーションの基本です。「ている」形を使って、現在の状態を明確に説明することが大切です。", "vi": "Báo cáo tình trạng của bệnh nhân một cách chính xác là cơ bản của giao tiếp giữa các nhân viên. Quan trọng là giải thích tình trạng hiện tại một cách rõ ràng bằng cách sử dụng dạng ている."}, "quiz": [{"question": {"ja": "「食べています」は何を表していますか？", "vi": "\"食べています\" biểu hiện cái gì?"}, "options": [{"ja": "過去に食べた", "vi": "Đã ăn trong quá khứ"},{"ja": "今、食べている状態である", "vi": "Đang ăn bây giờ"},{"ja": "将来、食べるつもりである", "vi": "Dự định ăn trong tương lai"},{"ja": "食べるのが好きである", "vi": "Thích ăn"}], "correct_answer": 1, "explanation": {"ja": "「ている」は現在進行中の状態を表します。\"食べています\"は、今、食べている最中であることを意味します。", "vi": "\"ている\" biểu hiện tình trạng đang tiến hành. \"食べています\" có nghĩa là đang ăn ngay bây giờ."}, "difficulty": "easy"}]}');
INSERT INTO lessons (id, course_id, unit, lesson_number, type, content) VALUES
(gen_random_uuid(), (SELECT id FROM courses WHERE title->>'ja' = 'JLPT N5 基本文法' LIMIT 1), 5, 1, 'grammar', '{"intro": {"ja": "能力や可能性を表す～ことができる を学びます。「患者さんは歩くことができます」など、患者さんの能力を確認する時に重要です。リハビリの進捗評価にも使われます。", "vi": "Học ~ことができる biểu hiện khả năng hoặc khả thi. \"Bệnh nhân có thể đi bộ\"... quan trọng khi xác nhận khả năng của bệnh nhân. Cũng được sử dụng để đánh giá tiến độ phục hồi chức năng."}, "patterns": [{"pattern": "動詞の基本形 + ことができる", "meaning": {"ja": "～することができる。能力や可能性を表す", "vi": "Có thể ~. Biểu hiện khả năng hoặc khả thi"}, "examples": [{"ja": "患者さんは歩くことができます。", "vi": "Bệnh nhân có thể đi bộ."},{"ja": "薬を飲むことができません。", "vi": "Không thể uống thuốc."}], "care_context": "患者さんの能力評価時：「トイレに行くことができますか？」「ペンで書くことができました。」", "explanation": {"ja": "ことができる は能力や可能性を表します。患者さんの回復状況を評価する時に使われます。", "vi": "ことができる biểu hiện khả năng hoặc khả thi. Được sử dụng khi đánh giá tình trạng phục hồi của bệnh nhân."}, "difficulty": "medium"}], "dialogue": ["介護職: 「今、自分で食べることができますか？」", "患者さん: 「はい、できるようになりました。」", "介護職: 「素晴らしい。トイレに行くこともできますか？」", "患者さん: 「いいえ、まだ危険です。」", "介護職: 「わかりました。もう少し訓練を続けましょう。」", "患者さん: 「ありがとうございます。頑張ります。」", "介護職: 「必ずできるようになります。一緒に頑張りましょう。」"], "key_phrases": [{"ja": "歩くことができます", "vi": "Có thể đi bộ"},{"ja": "食べることができません", "vi": "Không thể ăn"},{"ja": "書くことができました", "vi": "Có thể viết"},{"ja": "トイレに行くことができますか", "vi": "Có thể đi nhà vệ sinh không"}], "cultural_note": {"ja": "患者さんの能力評価は、リハビリの計画や目標設定に重要です。患者さんが何ができるのか、何ができないのかを正確に把握することで、適切なケアプランが立てられます。", "vi": "Đánh giá khả năng của bệnh nhân là quan trọng đối với kế hoạch phục hồi chức năng và đặt mục tiêu. Hiểu rõ bệnh nhân có thể làm gì và không thể làm gì giúp lập kế hoạch chăm sóc phù hợp."}, "quiz": [{"question": {"ja": "「ことができます」は何を示していますか？", "vi": "\"ことができます\" chỉ cái gì?"}, "options": [{"ja": "義務を示す", "vi": "Chỉ nghĩa vụ"},{"ja": "禁止を示す", "vi": "Chỉ cấm"},{"ja": "能力や可能性を示す", "vi": "Chỉ khả năng hoặc khả thi"},{"ja": "過去を示す", "vi": "Chỉ quá khứ"}], "correct_answer": 2, "explanation": {"ja": "ことができる は能力や可能性を表します。患者さんが何かをすることができるかどうかを示します。", "vi": "ことができる biểu hiện khả năng hoặc khả thi. Nó chỉ bệnh nhân có thể làm gì hoặc không."}, "difficulty": "medium"}]}');
INSERT INTO lessons (id, course_id, unit, lesson_number, type, content) VALUES
(gen_random_uuid(), (SELECT id FROM courses WHERE title->>'ja' = 'JLPT N5 基本文法' LIMIT 1), 5, 2, 'grammar', '{"intro": {"ja": "て形は日本語の最も基本的な活用です。複数の動作をつなぎ、リクエストの形、継続を示します。介護職として毎日使う、最も重要な文法です。", "vi": "Dạng て là hoạt hóa cơ bản nhất của tiếng Nhật. Kết nối nhiều hành động, dạng yêu cầu, chỉ tiếp diễn. Là ngữ pháp quan trọng nhất mà nhân viên chăm sóc sử dụng hàng ngày."}, "patterns": [{"pattern": "て形 + 形式", "meaning": {"ja": "複数の動作を順序立てる、リクエスト、継続を示す", "vi": "Sắp xếp nhiều hành động, biểu hiện yêu cầu, tiếp diễn"}, "examples": [{"ja": "起きて、洗顔して、朝食を食べてください。", "vi": "Thức dậy, rửa mặt, ăn bữa sáng."},{"ja": "ゆっくり歩いていってください。", "vi": "Đi từ từ."}], "care_context": "複数の指示をつなぐ：「薬を飲んで、休んでください。」リクエスト：「ちょっと待っていてください。」", "explanation": {"ja": "て形は様々な文法形式に使われます。これが一つの最も応用的な活用形です。", "vi": "Dạng て được sử dụng trong nhiều dạng ngữ pháp. Đây là hoạt hóa linh hoạt nhất."}, "difficulty": "hard"}], "dialogue": ["介護職: 「朝ですから、起きて、顔を洗って、朝食を食べてください。」", "患者さん: 「わかりました。」", "介護職: 「ゆっくり歩いていってください。」", "患者さん: 「ありがとうございます。」", "介護職: 「ちょっと待っていてください。」", "患者さん: 「はい。」", "介護職: 「もうすぐ薬を持ってきます。」"], "key_phrases": [{"ja": "起きて、洗顔して、朝食", "vi": "Thức dậy, rửa mặt, bữa sáng"},{"ja": "ゆっくり歩いていく", "vi": "Đi từ từ"},{"ja": "ちょっと待っていて", "vi": "Chờ một chút"},{"ja": "薬を飲んで、休む", "vi": "Uống thuốc, rồi nghỉ"}], "cultural_note": {"ja": "て形はあらゆる日本語表現の基礎です。これを正確に使いこなすことで、患者さんと効果的にコミュニケーションが取れます。", "vi": "Dạng て là nền tảng của tất cả các biểu thức tiếng Nhật. Sử dụng chính xác nó cho phép giao tiếp hiệu quả với bệnh nhân."}, "quiz": [{"question": {"ja": "て形の主な用途は何ですか？", "vi": "Ứng dụng chính của dạng て là gì?"}, "options": [{"ja": "一つの動作だけを説明する", "vi": "Giải thích chỉ một hành động"},{"ja": "複数の動作をつなぎ、順序立てる", "vi": "Kết nối nhiều hành động, sắp xếp theo thứ tự"},{"ja": "過去を説明する", "vi": "Giải thích quá khứ"},{"ja": "将来を説明する", "vi": "Giải thích tương lai"}], "correct_answer": 1, "explanation": {"ja": "て形は複数の動作をつなぎ、順序立てます。また、リクエストの形や継続を示します。", "vi": "Dạng て kết nối nhiều hành động và sắp xếp thứ tự. Nó cũng biểu hiện dạng yêu cầu và tiếp diễn."}, "difficulty": "hard"}]}');
INSERT INTO lessons (id, course_id, unit, lesson_number, type, content) VALUES
(gen_random_uuid(), (SELECT id FROM courses WHERE title->>'ja' = 'JLPT N5 基本文法' LIMIT 1), 6, 1, 'grammar', '{"intro": {"ja": "～たい は、誰かの望みや欲望を表します。「患者さんが何をしたいのか」を理解することは、患者さんのニーズを把握するために重要です。患者さんの人生の質を高めるためのコミュニケーション方法です。", "vi": "~たい biểu hiện mong muốn hoặc mục tiêu của ai đó. Hiểu \"bệnh nhân muốn làm gì\" là quan trọng để nắm bắt nhu cầu của bệnh nhân. Đây là phương pháp giao tiếp để nâng cao chất lượng cuộc sống của bệnh nhân."}, "patterns": [{"pattern": "動詞 + たい", "meaning": {"ja": "～したい。誰かの望み、欲望を表す", "vi": "Muốn ~. Biểu hiện mong muốn hoặc mục tiêu"}, "examples": [{"ja": "散歩に行きたいです。", "vi": "Muốn đi dạo."},{"ja": "家に帰りたいです。", "vi": "Muốn về nhà."}], "care_context": "患者さんのニーズを聞く：「今、何がしたいですか？」「どこに行きたいですか？」", "explanation": {"ja": "たい は個人の望みや欲望を表します。患者さんの希望を聞くことで、患者さんを尊重し、個別ケアが実現できます。", "vi": "たい biểu hiện mong muốn hoặc đích cá nhân. Nghe lời mong muốn của bệnh nhân thể hiện sự tôn trọng và thực hiện chăm sóc cá nhân."}, "difficulty": "medium"}], "dialogue": ["介護職: 「今、何がしたいですか？」", "患者さん: 「散歩に行きたいです。」", "介護職: 「素晴らしい。一緒に散歩に行きましょう。」", "患者さん: 「ありがとうございます。」", "介護職: 「どこに行きたいですか？」", "患者さん: 「公園に行きたいです。」", "介護職: 「わかりました。では、準備しましょう。」"], "key_phrases": [{"ja": "散歩に行きたい", "vi": "Muốn đi dạo"},{"ja": "家に帰りたい", "vi": "Muốn về nhà"},{"ja": "本を読みたい", "vi": "Muốn đọc sách"},{"ja": "何がしたいですか", "vi": "Bạn muốn làm gì"}], "cultural_note": {"ja": "患者さんの望みや欲望を尊重することは、介護の最も大切な原則の一つです。患者さんが何をしたいのかを聞き、その希望を実現することで、患者さんの尊厳と人生の質が向上します。", "vi": "Tôn trọng mong muốn của bệnh nhân là một trong những nguyên tắc quan trọng nhất của chăm sóc. Lắng nghe bệnh nhân muốn làm gì và thực hiện mong muốn đó nâng cao nhân phẩm và chất lượng cuộc sống."}, "quiz": [{"question": {"ja": "「散歩に行きたいです」は何を示していますか？", "vi": "\"散歩に行きたいです\" chỉ cái gì?"}, "options": [{"ja": "過去に散歩に行った", "vi": "Đã đi dạo trong quá khứ"},{"ja": "散歩に行く予定", "vi": "Dự định đi dạo"},{"ja": "散歩に行きたい、という個人の望み", "vi": "Mong muốn đi dạo"},{"ja": "散歩に行かなければならない", "vi": "Phải đi dạo"}], "correct_answer": 2, "explanation": {"ja": "たい は個人の望みや欲望を表します。患者さんが散歩に行きたいという希望を示しています。", "vi": "たい biểu hiện mong muốn hoặc đích cá nhân. Nó chỉ bệnh nhân mong muốn đi dạo."}, "difficulty": "medium"}]}');
INSERT INTO lessons (id, course_id, unit, lesson_number, type, content) VALUES
(gen_random_uuid(), (SELECT id FROM courses WHERE title->>'ja' = 'JLPT N5 基本文法' LIMIT 1), 6, 2, 'grammar', '{"intro": {"ja": "～べき は、義務や推奨を表します。「患者さんはこれをすべき」など、医学的推奨や健康管理の指示に使われます。介護職として患者さんにアドバイスする時の重要な表現です。", "vi": "~べき biểu hiện nghĩa vụ hoặc khuyến cáo. \"Bệnh nhân nên làm điều này\"... được sử dụng cho khuyến cáo y tế hoặc chỉ dẫn quản lý sức khỏe. Là biểu thức quan trọng khi nhân viên chăm sóc tư vấn bệnh nhân."}, "patterns": [{"pattern": "動詞 + べき", "meaning": {"ja": "～すべき。義務、推奨、当然。～しなければならない", "vi": "Nên ~. Nghĩa vụ, khuyến cáo, tất nhiên"}, "examples": [{"ja": "毎日運動すべきです。", "vi": "Nên tập luyện hàng ngày."},{"ja": "薬を毎日飲むべきです。", "vi": "Nên uống thuốc hàng ngày."}], "care_context": "患者さんへのアドバイス：「塩分を控えるべきです。」「ゆっくり歩くべきです。」", "explanation": {"ja": "べき は義務や推奨を強く示します。医学的に必要なアドバイスをする時に使われます。", "vi": "べき biểu hiện mạnh mẽ nghĩa vụ hoặc khuyến cáo. Được sử dụng khi đưa lời khuyên y tế cần thiết."}, "difficulty": "hard"}], "dialogue": ["介護職: 「塩分を控えるべきです。」", "患者さん: 「わかりました。」", "介護職: 「毎日運動すべきです。」", "患者さん: 「頑張ります。」", "介護職: 「薬を忘れずに飲むべきです。」", "患者さん: 「ありがとうございます。」", "介護職: 「あなたの健康のために、これらをすべきです。」"], "key_phrases": [{"ja": "塩分を控えるべき", "vi": "Nên giảm muối"},{"ja": "毎日運動すべき", "vi": "Nên tập luyện hàng ngày"},{"ja": "薬を飲むべき", "vi": "Nên uống thuốc"},{"ja": "ゆっくり歩くべき", "vi": "Nên đi từ từ"}], "cultural_note": {"ja": "介護職が患者さんに医学的アドバイスをする時は、～べき を使って推奨や義務を明確に示すことが大切です。しかし、患者さんの自主性や望みも尊重する必要があります。", "vi": "Khi nhân viên chăm sóc đưa lời khuyên y tế cho bệnh nhân, quan trọng là sử dụng ~べき để chỉ rõ khuyến cáo hoặc nghĩa vụ. Tuy nhiên, cũng cần tôn trọng sự tự chủ và mong muốn của bệnh nhân."}, "quiz": [{"question": {"ja": "「毎日運動すべきです」は何を示していますか？", "vi": "\"毎日運動すべきです\" chỉ cái gì?"}, "options": [{"ja": "患者さんが運動したい", "vi": "Bệnh nhân muốn tập luyện"},{"ja": "患者さんは毎日運動する必要がある、という推奨", "vi": "Khuyến cáo bệnh nhân nên tập luyện hàng ngày"},{"ja": "患者さんは運動できない", "vi": "Bệnh nhân không thể tập luyện"},{"ja": "過去に運動した", "vi": "Đã tập luyện trong quá khứ"}], "correct_answer": 1, "explanation": {"ja": "べき は義務や推奨を表します。患者さんが毎日運動すべき、という医学的推奨を示しています。", "vi": "べき biểu hiện nghĩa vụ hoặc khuyến cáo. Nó chỉ khuyến cáo y tế rằng bệnh nhân nên tập luyện hàng ngày."}, "difficulty": "hard"}]}');
